callGraph.callee:
execFileSync(
				"zsh",
				["-ic", `source "${wrapperPath}"; node`],
				{
					encoding: "utf-8",
					env: {
						HOME: homeDir,
						PATH: `${systemBinDir}:/usr/bin:/bin`,
						SUPERSET_ORIG_ZDOTDIR: homeDir,
						ZDOTDIR: integrationZshDir,
					},
				},
			).trim

SUPERSET_MANAGED_BINARIES.map(
			(name: SupersetManagedBinary) =>
				`functions -q ${name}; and functions -e ${name}
function ${name}
  set -l _superset_wrapper "${escapedBinDir}/${name}"
  if test -x "$_superset_wrapper"; and not test -d "$_superset_wrapper"
    "$_superset_wrapper" $argv
  else
    command ${name} $argv
  end
end`,
		).join

SUPERSET_MANAGED_BINARIES.map(
		(name: SupersetManagedBinary) =>
			`unalias ${name} 2>/dev/null || true
${name}() {
  _superset_wrapper=${quoteShellLiteral(`${binDir}/${name}`)}
  if [ -x "$_superset_wrapper" ] && [ ! -d "$_superset_wrapper" ]; then
    "$_superset_wrapper" "$@"
  else
    command ${name} "$@"
  fi
}`,
	).join

autoUpdater
		.checkForUpdates()
		.then((result) => {
			if (
				!result?.updateInfo ||
				gte(app.getVersion(), result.updateInfo.version)
			) {
				emitStatus(AUTO_UPDATE_STATUS.IDLE);
				dialog.showMessageBox({
					type: "info",
					title: "No Updates",
					message: "You're up to date!",
					detail: `Version ${app.getVersion()} is the latest version.`,
				});
			}
		})
		.catch
